-- =========================================================================
-- ESCO MIGRATION — PHASE 4: PAYMENTS + ROUTES + DISPATCHES + ORDERS
-- =========================================================================
-- routes:     8
-- payments:   61
-- dispatches: 2
-- orders:     1
--
-- ВАЖЛИВО:
--   ALTER dispatches DROP NOT NULL для route_id, vehicle_id —
--   у xlsx обидва Відправки мають порожні RTE_ID/AUTO_ID,
--   без DROP NOT NULL 2 рядки не зайдуть → втратимо.
--
-- Порядок: routes → payments/dispatches/orders (FK lookup'и).
-- =========================================================================

BEGIN;

-- ── Schema changes ──────────────────────────────────────────────
ALTER TABLE public.routes ADD COLUMN IF NOT EXISTS extra_data jsonb;
ALTER TABLE public.dispatches ALTER COLUMN route_id DROP NOT NULL;
ALTER TABLE public.dispatches ALTER COLUMN vehicle_id DROP NOT NULL;

-- ── UNIQUE indexes ──────────────────────────────────────────────
CREATE UNIQUE INDEX IF NOT EXISTS routes_tenant_rte_uidx ON public.routes (tenant_id, rte_id);
CREATE UNIQUE INDEX IF NOT EXISTS payments_tenant_pay_uidx ON public.payments (tenant_id, pay_id);
CREATE UNIQUE INDEX IF NOT EXISTS dispatches_tenant_disp_uidx ON public.dispatches (tenant_id, dispatch_id);
CREATE UNIQUE INDEX IF NOT EXISTS orders_tenant_order_uidx ON public.orders (tenant_id, order_id);

-- ── routes (8) ───────────────────────────────────

-- ── payments (61) ───────────────────────────────

-- ── dispatches (2) ───────────────────────────

-- ── orders (1) ───────────────────────────────────

COMMIT;

NOTIFY pgrst, 'reload schema';